use std::{env,path::PathBuf};use schema_engine::Runtime;use signal_schema::{Request,encode_reply,encode_request};use signal_sema_storage::{FixtureScope,SlotIdentifier};use tokio::{io::{AsyncReadExt,AsyncWriteExt},net::{UnixListener,UnixStream}};
#[tokio::main]async fn main()->Result<(),Box<dyn std::error::Error>>{let mut a=env::args().skip(1);match a.next().as_deref(){Some("daemon")=>{let socket=PathBuf::from(a.next().unwrap_or_else(||"/tmp/new-language-engine/schema.sock".into()));let sema=PathBuf::from(a.next().unwrap_or_else(||"/tmp/new-language-engine/sema.sock".into()));if let Some(p)=socket.parent(){std::fs::create_dir_all(p)?}let _=std::fs::remove_file(&socket);let listener=UnixListener::bind(socket)?;let runtime=Runtime::new(sema);loop{let(s,_)=listener.accept().await?;let r=runtime.clone();tokio::spawn(async move{let _=serve(s,r).await;});}},Some("ingest")=>{let socket=PathBuf::from(a.next().ok_or("socket")?);let file=PathBuf::from(a.next().ok_or("schema file")?);let text=tokio::fs::read_to_string(file).await?;let reply=client(&socket,&Request::IngestTypeSchema{scope:FixtureScope(1),slot:SlotIdentifier(1),legacy_text:text}).await?;println!("{reply:?}");Ok(())},_=>Err("usage: schema-engine daemon [socket] [sema-socket] | ingest <socket> <file>".into())}}
async fn serve(mut s:UnixStream,r:Runtime)->Result<(),Box<dyn std::error::Error>>{let n=s.read_u32_le().await? as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;let q=rkyv::from_bytes::<Request,rkyv::rancor::Error>(&b)?;let bytes=encode_reply(&r.request(q).await?).map_err(|e|format!("encode: {e}"))?;s.write_u32_le(bytes.len()as u32).await?;s.write_all(&bytes).await?;Ok(())}
async fn client(socket:&PathBuf,q:&Request)->Result<signal_schema::Reply,Box<dyn std::error::Error>>{let mut s=UnixStream::connect(socket).await?;let b=encode_request(q).map_err(|e|format!("encode: {e}"))?;s.write_u32_le(b.len()as u32).await?;s.write_all(&b).await?;let n=s.read_u32_le().await?as usize;let mut b=vec![0;n];s.read_exact(&mut b).await?;Ok(rkyv::from_bytes::<signal_schema::Reply,rkyv::rancor::Error>(&b)?)}
